mapper.select:
SELECT r.id, r.name, r.cas_number, r.specification, r.purity, r.category_id, r.unit, r.storage_condition, r.safety_stock_threshold, r.warning_advance_days, r.status, r.create_time, (SELECT COALESCE(SUM(current_quantity), 0) FROM reagent_batch WHERE reagent_id = r.id AND status IN (0, 1)) AS total_stock FROM reagent r
AND (r.name LIKE CONCAT('%', #{keyword}, '%') OR r.cas_number LIKE CONCAT('%', #{keyword}, '%'))
AND r.category_id = #{categoryId}
AND r.status = #{status}
AND r.id IN ( SELECT DISTINCT reagent_id FROM reagent_batch WHERE supplier_id = #{supplierId} )
ORDER BY r.id DESC
